import{_ as t,o as e,c as a,Q as o}from"./chunks/framework.b67c47e6.js";const p=JSON.parse('{"title":"Account Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/index.md","filePath":"guide/account/index.md","lastUpdated":1773939149000}'),i={name:"guide/account/index.md"},n=o('<h1 id="account-settings" tabindex="-1">Account Settings <a class="header-anchor" href="#account-settings" aria-label="Permalink to &quot;Account Settings&quot;">​</a></h1><p>The Account page lets you manage your personal settings, security, and notification preferences.</p><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><p>Your account page shows:</p><ul><li><strong>Username</strong> — Your login name.</li><li><strong>Production line</strong> — Your currently assigned production line.</li><li><strong>Production station</strong> — Your currently assigned station.</li><li><strong>Language</strong> — Interface language (if your admin has enabled multilanguage for your account).</li></ul><h2 id="two-factor-authentication-2fa" tabindex="-1">Two-Factor Authentication (2FA) <a class="header-anchor" href="#two-factor-authentication-2fa" aria-label="Permalink to &quot;Two-Factor Authentication (2FA)&quot;">​</a></h2><p>Enable 2FA to add an extra layer of security to your account. When enabled, you&#39;ll need to enter a one-time password (OTP) from your authenticator app each time you log in.</p><h3 id="setting-up-2fa" tabindex="-1">Setting Up 2FA <a class="header-anchor" href="#setting-up-2fa" aria-label="Permalink to &quot;Setting Up 2FA&quot;">​</a></h3><ol><li>Click <strong>Enable 2FA</strong> on the account page.</li><li>Scan the QR code with your authenticator app (Google Authenticator, Authy, etc.).</li><li>Enter the verification code to confirm setup.</li></ol><h3 id="disabling-2fa" tabindex="-1">Disabling 2FA <a class="header-anchor" href="#disabling-2fa" aria-label="Permalink to &quot;Disabling 2FA&quot;">​</a></h3><p>Click <strong>Disable 2FA</strong> and confirm. You&#39;ll need to authenticate to complete the action.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>Configure how you receive notifications from produuz.it:</p><ul><li><strong>Push / Browser notifications</strong> — Receive real-time alerts in your browser.</li><li><strong>Email notifications</strong> — Get email updates for production events and webhook triggers.</li></ul><p>Click the setup buttons to configure each notification channel.</p>',15),r=[n];function c(s,l,u,d,h,g){return e(),a("div",null,r)}const m=t(i,[["render",c]]);export{p as __pageData,m as default};
